CREATE TRIGGER LG_BNFLINE_INS_523_01 ON LG_523_01_BNFLINE
FOR INSERT
AS
DECLARE @BNACCREF  INT
DECLARE @AMOUNT    FLOAT
DECLARE @TRANSTYPE SMALLINT
DECLARE @TRCODE    SMALLINT
DECLARE @CLIENTREF INT
DECLARE @DT        DATETIME
DECLARE @SIGN      SMALLINT
DECLARE @TRNET     FLOAT
DECLARE @REPORTNET FLOAT
DECLARE @CANCELLED SMALLINT
DECLARE @TSTATE    SMALLINT
DECLARE @TDUEDATE  DATETIME
DECLARE @OPSTAT    SMALLINT
DECLARE @COSTTOT   FLOAT
DECLARE @BSMVTOT   FLOAT
DECLARE @REPCOSTTOT   FLOAT
DECLARE @REPBSMVTOT   FLOAT
DECLARE @TRCOSTTOT   FLOAT
DECLARE @TRBSMVTOT   FLOAT
DECLARE @BNTRANCOSTTOTINC SMALLINT
DECLARE @STATUS     SMALLINT
DECLARE @CSTRANSREF INT
DECLARE @COSTTYPE   SMALLINT
SELECT @BNACCREF  = I.BNACCREF,
       @AMOUNT    = I.AMOUNT,
       @TRANSTYPE = I.TRANSTYPE,
       @TRCODE    = I.TRCODE,
       @CLIENTREF = I.CLIENTREF,
       @DT        = I.DATE_,
       @SIGN      = I.SIGN,
       @TRNET     = I.TRNET,
       @REPORTNET = I.REPORTNET,
       @CANCELLED = I.CANCELLED,
       @TSTATE    = I.TRNSTATE,
       @TDUEDATE  = I.TRANSDUEDATE,
       @OPSTAT    = I.OPSTAT,
       @COSTTOT   = I.COSTTOT,
       @BSMVTOT   = I.BSMVTOT,
       @REPCOSTTOT  = I.REPCOSTTOT,
       @REPBSMVTOT  = I.REPBSMVTOT,
       @TRCOSTTOT   = I.TRCOSTTOT,
       @BNTRANCOSTTOTINC = I.BNTRANCOSTTOTINC,
       @TRBSMVTOT   = I.TRBSMVTOT,
       @STATUS = I.STATUS,
       @CSTRANSREF = I.CSTRANSREF,
       @COSTTYPE = I.COSTTYPE FROM INSERTED I
IF (@TRCODE = 3) OR (@TRCODE = 4)
 BEGIN
       IF (@COSTTYPE=2)
        BEGIN SELECT @AMOUNT = @AMOUNT + @BSMVTOT
              SELECT @REPORTNET =  @REPORTNET +  @REPBSMVTOT
              SELECT @TRNET =  @TRNET +  @TRBSMVTOT
        END
       ELSE IF (@BNTRANCOSTTOTINC=1)
        BEGIN
              SELECT @AMOUNT = @AMOUNT - @COSTTOT +  @BSMVTOT
              SELECT @REPORTNET =  @REPORTNET -  @REPCOSTTOT +  @REPBSMVTOT
              SELECT @TRNET =  @TRNET -  @TRCOSTTOT +  @TRBSMVTOT
        END
       ELSE
        BEGIN
              SELECT @AMOUNT = @AMOUNT + @COSTTOT +  @BSMVTOT
              SELECT @REPORTNET =  @REPORTNET +  @REPCOSTTOT +  @REPBSMVTOT
              SELECT @TRNET =  @TRNET +  @TRCOSTTOT +  @TRBSMVTOT
        END
 END
 IF (@TRCODE = 2)
 BEGIN SELECT @AMOUNT = @AMOUNT + @COSTTOT +  @BSMVTOT
       SELECT @REPORTNET =  @REPORTNET +  @REPCOSTTOT +  @REPBSMVTOT
       SELECT @TRNET =  @TRNET +  @TRCOSTTOT +  @TRBSMVTOT
 END
EXECUTE LG_UPDATE_BNTRANS_523_01 1, @BNACCREF, @AMOUNT, @TRANSTYPE, @TRCODE, @CLIENTREF, @DT,
                                 @SIGN, @TRNET, @REPORTNET, @CANCELLED, @TSTATE, @TDUEDATE, @OPSTAT, @STATUS, @CSTRANSREF, @COSTTYPE
